 if(!$error){$sql='INSERT INTO items (item_no,serial_no,related_items,found_at,location,found_department,found_by,quantity,category,name,brand,color,details,storage_location,status,delivered_at,delivery_method,delivered_by,delivery_form_no,recorded_by) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)';$values=[trim($_POST['item_no']),trim($_POST['serial_no']??''),trim($_POST['related_items']??''),$_POST['found_at'],trim($_POST['location']),trim($_POST['found_department']),trim($_POST['found_by']??''),max(1,(int)($_POST['quantity']??1)),$selectedDefinition['category'],$selectedDefinition['name'],trim($_POST['brand']??''),trim($_POST['color']??''),trim($_POST['details']??''),trim($_POST['storage_location']),trim($_POST['status']),($_POST['delivered_at']??'')?:null,trim($_POST['delivery_method']??''),trim($_POST['delivered_by']??''),trim($_POST['delivery_form_no']??''),$_SESSION['user']['name']];try{$stmt=db()->prepare($sql);$stmt->execute($values);redirect('index.php');}catch(PDOException $e){$error='Kayıt eklenemedi. Eşya numarası benzersiz olmalıdır.';}}
}
function posted(string $key,string $default=''):string{return e($_POST[$key]??$default);}
