<script>document.querySelectorAll('[data-search-select]').forEach(select=>{const hidden=select.querySelector('input[type=hidden]'),trigger=select.querySelector('.search-select-trigger'),caption=trigger.querySelector('span'),search=select.querySelector('.search-select-input'),options=[...select.querySelectorAll('[role=option]')],empty=select.querySelector('.search-select-empty');const selected=options.find(o=>o.dataset.value===hidden.value);if(selected)caption.textContent=selected.dataset.label;const close=()=>{select.classList.remove('open');trigger.setAttribute('aria-expanded','false')};trigger.addEventListener('click',()=>{const opening=!select.classList.contains('open');select.classList.toggle('open',opening);trigger.setAttribute('aria-expanded',String(opening));if(opening){search.value='';options.forEach(o=>o.hidden=false);empty.hidden=true;search.focus()}});search.addEventListener('input',()=>{const term=search.value.toLocaleLowerCase('tr-TR').trim();let visible=0;options.forEach(o=>{o.hidden=!o.dataset.label.toLocaleLowerCase('tr-TR').includes(term);if(!o.hidden)visible++});empty.hidden=visible!==0});options.forEach(o=>o.addEventListener('click',()=>{hidden.value=o.dataset.value;caption.textContent=o.dataset.label;options.forEach(x=>x.setAttribute('aria-selected',String(x===o)));close()}));document.addEventListener('click',e=>{if(!select.contains(e.target))close()})});</script><script src="<?=url('assets/required.js')?>"></script></body></html>
